// src/components/NavBar.js
import React from 'react';
import '../'; // Optional: You can style your NavBar

const NavBar = () => {
  return (
    <nav>
      <ul>
        <li><a href="#home">Home</a></li>
        <li><a href="#about">About</a></li>
        <li><a href="#contact">Contact</a></li>
      </ul>
    </nav>
  );
};

export default NavBar;
